import{_ as a,o as r,c as t,a7 as i}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"Proliferation Frenzy","description":"","frontmatter":{},"headers":[],"relativePath":"en/modes/proliferation.md","filePath":"en/modes/proliferation.md","lastUpdated":1775394001000}'),s={name:"en/modes/proliferation.md"};function o(n,e,l,m,d,h){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="proliferation-frenzy" tabindex="-1">Proliferation Frenzy <a class="header-anchor" href="#proliferation-frenzy" aria-label="Permalink to &quot;Proliferation Frenzy&quot;">​</a></h1><p><strong>Proliferation Frenzy</strong> (融灾禁区 / Erosion Disaster Zone) is a multi-team endgame challenge mode in Morimens.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Proliferation Frenzy is the ultimate test of your roster depth. It requires assembling multiple teams using non-duplicate Awakeners, Wheels, and Key Orders to clear five sequential challenge stages.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li><strong>Multiple Teams</strong>: Build several distinct teams — no Awakener, Wheel, or Key Order can be used more than once across all teams</li><li><strong>Roster Depth</strong>: Success depends on having a deep roster of built characters</li><li><strong>Strategic Planning</strong>: Team composition across all slots matters more than any single team</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Spread your strongest Awakeners across teams rather than stacking one team</li><li>Plan your Wheel and Key Order assignments before starting</li><li>Consider which stages benefit most from specific Realm synergies</li><li>Having at least 2-3 fully invested teams is recommended before attempting</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Game Modes Overview</a></li><li><a href="./combat.html">Combat System</a></li><li><a href="./../awakeners/team-building.html">Team Building</a></li></ul>',10)])])}const f=a(s,[["render",o]]);export{u as __pageData,f as default};
